		Update(const std::uint32_t elapsedMilliseconds,
			const ComponentMask& componentMask,
			const std::vector<uint32_t>& entityIds,
			T& t,
			Ts... ts);



	template<std::size_t Index1, typename T, typename... Ts>
	std::enable_if_t<Index1 != sizeof...(Cs)>
		Update(const std::uint32_t elapsedMilliseconds,
			const ComponentMask& componentMask,
			const std::vector<uint32_t>& entityIds,
			T& t,
			Ts... ts);

	virtual void Update(const std::uint32_t elapsedMilliseconds,
		Archetype* archetype) override;




	ECS& ecs_;
	ComponentMask componentMask_;
	Func func_;
	bool funcStatus_;
};

template<class... Cs>
System<Cs...>::System(ECS& ecs, const std::uint8_t& layer)
	: ecs_(ecs), funcStatus_(false)
{
	ecs_.RegisterSystem(layer, this);
	((componentMask_.AddComponent(GetTypeID<Cs>())), ...);
}

template<class... Cs>
ComponentMask System<Cs...>::GetComponentMask() const
{
	return componentMask_;
}

template<class... Cs>
void System<Cs...>::Action(Func func)
{
	func_ = func;
	funcStatus_ = true;
}

template<class... Cs>
void System<Cs...>::Update(const std::uint32_t elapsedMilliseconds, Archetype* archetype)
{
	if (funcStatus_)
		Update<0>(elapsedMilliseconds,
			archetype->componentMask,
			archetype->entityIds,
			archetype->componentData);
}

template<class... Cs>
template<std::size_t Index, typename T, typename... Ts>
std::enable_if_t<Index != sizeof...(Cs)>
System<Cs...>::Update(const std::uint32_t elapsedMilliseconds,
	const ComponentMask& componentMask,
	const std::vector<uint32_t>& entityIds,
	T& t,
	Ts... ts)
{
	using ComponentType = typename std::tuple_element<Index, std::tuple<Cs...>>::type;
	std::size_t thisTypeCS = Component<ComponentType>::GetTypeID();

	std::size_t index2 = 0;
	for (int i = 0; i < thisTypeCS; i++) {
		if (componentMask.GetBitsetMask().test(i)) {
			index2++;
		}
	}

	Update<Index + 1>(elapsedMilliseconds,
		componentMask,
		entityIds,
		t,
		ts...,
		reinterpret_cast<ComponentType*>(&t[index2][0]));

}

